    static int player = 1; // By default player 1 starts
    static int choice; // User's choice for position to mark
    static int flag = 0; // Check who has won
    static void Main(string[] args)
    {
        do
        {
            Console.Clear(); // Whenever loop restarts we clear the console
            Console.WriteLine("Player 1: X and Player 2: O");
            Console.WriteLine("\n");
            if (player % 2 == 0)
            {
                Console.WriteLine("Turn player 2");
            }
            else
            {
                Console.WriteLine("Turn player 1");
            }
            Console.WriteLine("\n");
            Board();

            // Checking that position is marked already or not
            bool parseSuccess = Int32.TryParse(Console.ReadLine(), out choice);
            if (!parseSuccess || arr[choice] != choice.ToString())
            {
                Console.WriteLine("Sorry the row {0} is already marked with {1}", choice, arr[choice]);
                Console.ReadKey();
            }

            if (player % 2 == 0)
            {
                arr[choice] = 'O';
                player++;
            }
            else
            {
                arr[choice] = 'X';
                player++;
            }
            flag = CheckWin();
        }
        while (flag != 1 && flag != -1);

        Console.Clear();
        Board();
        if (flag == 1)
        {
            Console.WriteLine("Player {0} has won", (player % 2) + 1);
        }
        else
        {
            Console.WriteLine("Draw");
        }
        Console.ReadLine();
    }
    private static void Board()
    {
        Console.WriteLine("     |     |      ");
        Console.WriteLine("  {0}  |  {1}  |  {2}", arr[1], arr[2], arr[3]);
        Console.WriteLine("_____|_____|_____ ");
        Console.WriteLine("     |     |      ");
        Console.WriteLine("  {0}  |  {1}  |  {2}", arr[4], arr[5], arr[6]);
        Console.WriteLine("_____|_____|_____ ");
        Console.WriteLine("     |     |      ");
        Console.WriteLine("  {0}  |  {1}  |  {2}", arr[7], arr[8], arr[9]);
        Console.WriteLine("     |     |      ");
    }

    private static int CheckWin()
    {
        #region Horzontal Winning Condtion
        // Winning Condition For First Row   
        if (arr[1] == arr[2] && arr[2] == arr[3])
        {
            return 1;
        }
        // Winning Condition For Second Row   
        else if (arr[4] == arr[5] && arr[5] == arr[6])
        {
            return 1;
        }
        // Winning Condition For Third Row   
        else if (arr[6] == arr[7] && arr[7] == arr[8])
        {
            return 1;
        }
        #endregion

        #region Vertical Winning Condtion
        // Winning Condition For First Column       
        else if (arr[1] == arr[4] && arr[4] == arr[7])
        {
            return 1;
        }
        // Winning Condition For Second Column  
        else if (arr[2] == arr[5] && arr[5] == arr[8])
        {
            return 1;
        }
        // Winning Condition For Third Column  
        else if (arr[3] == arr[6] && arr[6] == arr[9])
        {
            return 1;
        }
        #endregion

        #region Diagonal Winning Condition
