const axios = require('axios');
const yargs = require('yargs');

// Read the kubeconfig file.
const kubeconfigPath = path.join(process.env.HOME, '.kube', 'config');
const kubeconfig = JSON.parse(fs.readFileSync(kubeconfigPath));

// Get the current context from the kubeconfig.
const currentContext = kubeconfig.contexts.find(
  (context) => context.name === kubeconfig['current-context']
);

// Get the cluster and user information for the current context.
const cluster = kubeconfig.clusters.find(
  (cluster) => cluster.name === currentContext.context.cluster
);
const user = kubeconfig.users.find(
  (user) => user.name === currentContext.context.user
);

// Configure axios to use the Kubernetes API server and authentication details.
const api = axios.create({
  baseURL: cluster.cluster.server,
  headers: {
    Authorization: `Bearer ${user.user.token}`,
  },
  httpsAgent: new (require('https').Agent)({ rejectUnauthorized: false }),
});

async function getPods(namespace) {
  try {
    const response = await api.get(`/api/v1/namespaces/${namespace}/pods`);
    return response.data.items;
  } catch (error) {
    console.error('Error fetching pods:', error.message);
    process.exit(1);
  }
}

async function main() {
  const argv = yargs.option('namespace', {
    alias: 'n',
    description: 'Namespace to query for running pods',
    type: 'string',
    demandOption: true,
  }).argv;

